<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_inventory','manage_inventory']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_inventory');$edit=null;if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$id=(int)($_POST['id']??0);$data=[trim($_POST['sku']??''),trim($_POST['item_name']??''),trim($_POST['category']??''),trim($_POST['unit']??''),(float)($_POST['quantity']??0),(float)($_POST['min_quantity']??0),(float)($_POST['unit_cost']??0),trim($_POST['location']??''),trim($_POST['status']??'active'),trim($_POST['notes']??'')];if($data[1]==='')throw new RuntimeException('Item name required.');if($id){$pdo->prepare("UPDATE mb_inventory_items SET sku=?,item_name=?,category=?,unit=?,quantity=?,min_quantity=?,unit_cost=?,location=?,status=?,notes=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Inventory item updated.');}else{$pdo->prepare("INSERT INTO mb_inventory_items (sku,item_name,category,unit,quantity,min_quantity,unit_cost,location,status,notes) VALUES (?,?,?,?,?,?,?,?,?,?)")->execute($data);mb_set_success('Inventory item created.');}}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_inventory_items WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Inventory item deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_inventory_items WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $q=trim($_GET['q']??'');$where='';$params=[];if($q!==''){$where="WHERE sku LIKE ? OR item_name LIKE ? OR category LIKE ? OR location LIKE ?";$like="%$q%";$params=[$like,$like,$like,$like];}$st=$pdo->prepare("SELECT *, quantity*unit_cost total_value FROM mb_inventory_items $where ORDER BY item_name ASC");$st->execute($params);$rows=$st->fetchAll(PDO::FETCH_ASSOC);$tot=$pdo->query("SELECT COUNT(*) c, COALESCE(SUM(quantity*unit_cost),0) value, SUM(CASE WHEN quantity<=min_quantity THEN 1 ELSE 0 END) low_stock FROM mb_inventory_items")->fetch(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Inventory','Inventory');?><?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="row g-3 mb-3"><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Items</div><div class="mb-stat-value"><?=(int)$tot['c']?></div></div></div><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Inventory Value</div><div class="mb-stat-value">₱<?=mb_money($tot['value'])?></div></div></div><div class="col-md-4"><div class="mb-stat"><div class="mb-stat-label">Low Stock</div><div class="mb-stat-value"><?=(int)$tot['low_stock']?></div></div></div></div><div class="mb-card"><div class="mb-card-header"><form class="mb-toolbar"><input class="form-control mb-search" name="q" value="<?=htmlspecialchars($q)?>" placeholder="Search inventory"><button class="btn btn-outline-secondary">Search</button></form><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="itemModal">New Item</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>SKU</th><th>Item</th><th>Category</th><th>Qty</th><th>Min</th><th>Unit Cost</th><th>Value</th><th>Location</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr class="<?=((float)$r['quantity'] <= (float)$r['min_quantity'])?'table-warning':''?>"><td><?=htmlspecialchars($r['sku'])?></td><td><strong><?=htmlspecialchars($r['item_name'])?></strong><div class="small text-muted"><?=htmlspecialchars($r['unit'])?></div></td><td><?=htmlspecialchars($r['category'])?></td><td><?=mb_money($r['quantity'])?></td><td><?=mb_money($r['min_quantity'])?></td><td>₱<?=mb_money($r['unit_cost'])?></td><td>₱<?=mb_money($r['total_value'])?></td><td><?=htmlspecialchars($r['location'])?></td><td><span class="mb-badge <?=((float)$r['quantity'] <= (float)$r['min_quantity'])?'warn':'success'?>"><?=htmlspecialchars($r['status'])?></span></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete item?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="10" class="text-center text-muted py-4">No inventory items.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="itemModal"><div class="modal-dialog modal-lg"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><div class="modal-header"><h5 class="modal-title"><?=$edit?'Edit':'New'?> Inventory Item</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>SKU<input class="form-control" name="sku" value="<?=htmlspecialchars($edit['sku']??'')?>"></label><label>Item Name<input required class="form-control" name="item_name" value="<?=htmlspecialchars($edit['item_name']??'')?>"></label><label>Category<input class="form-control" name="category" value="<?=htmlspecialchars($edit['category']??'')?>"></label><label>Unit<input class="form-control" name="unit" value="<?=htmlspecialchars($edit['unit']??'')?>"></label><label>Quantity<input type="number" step="0.01" class="form-control" name="quantity" value="<?=htmlspecialchars($edit['quantity']??'0')?>"></label><label>Minimum Quantity<input type="number" step="0.01" class="form-control" name="min_quantity" value="<?=htmlspecialchars($edit['min_quantity']??'0')?>"></label><label>Unit Cost<input type="number" step="0.01" class="form-control" name="unit_cost" value="<?=htmlspecialchars($edit['unit_cost']??'0')?>"></label><label>Location<input class="form-control" name="location" value="<?=htmlspecialchars($edit['location']??'')?>"></label><label>Status<input class="form-control" name="status" value="<?=htmlspecialchars($edit['status']??'active')?>"></label><label class="full">Notes<textarea class="form-control" name="notes"><?=htmlspecialchars($edit['notes']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Item</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('itemModal')).show();<?php endif;?></script><?php mb_workspace_footer();?>